#include<bits/stdc++.h>
using namespace std;
int a[100001],n,m,ans;
int find(int x){
	if(a[x]==0){
		return x;
	}else{
		return a[x]=find(a[x]);
	}
}
void up(int x,int y){
	int fx=find(x);
	int fy=find(y);
    if(fx==fy) return;
	a[fy]=fx;
}
int main(){
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		int x,y;
		cin>>x>>y;
		up(x,y);
	}
	for(int i=1;i<=n;i++){
		if(a[i]==0){
            ans++;
		}
	}
	cout<<ans;
	return 0;
}
